from functools import lru_cache

class Solution:
    def minNumberOfSemesters(self, n, relations, k):
        prereq = [0] * n
        for a, b in relations:
            prereq[b - 1] |= (1 << (a - 1))
        full = (1 << n) - 1

        @lru_cache(maxsize=None)
        def solve(mask):
            if mask == full:
                return 0
            avail = 0
            for i in range(n):
                if not (mask & (1 << i)) and (prereq[i] & mask) == prereq[i]:
                    avail |= (1 << i)
            best = None
            sub = avail
            while sub:
                if sub.bit_count() <= k:
                    candidate = 1 + solve(mask | sub)
                    if best is None or candidate < best:
                        best = candidate
                sub = (sub - 1) & avail
            return best

        return solve(0)

