class Solution:
    def minNumberOfSemesters(self, n, relations, k):
        prereq = [0] * n
        for a, b in relations:
            prereq[b - 1] |= (1 << (a - 1))
        full = (1 << n) - 1
        dp = [float('inf')] * (1 << n)
        dp[0] = 0
        for mask in range(1 << n):
            if dp[mask] == float('inf') or mask == full:
                continue
            avail = 0
            for i in range(n):
                if not (mask & (1 << i)) and (prereq[i] & mask) == prereq[i]:
                    avail |= (1 << i)
            sub = avail
            while sub:
                if sub.bit_count() <= k:
                    new_mask = mask | sub
                    if dp[mask] + 1 < dp[new_mask]:
                        dp[new_mask] = dp[mask] + 1
                sub = (sub - 1) & avail
        return dp[full]

