var minNumberOfSemesters = function(n, relations, k) {
    const prereq = new Array(n).fill(0);
    for (const [a, b] of relations) {
        prereq[b - 1] |= (1 << (a - 1));
    }
    const full = (1 << n) - 1;
    const dp = new Array(1 << n).fill(Infinity);
    dp[0] = 0;
    for (let mask = 0; mask < (1 << n); mask++) {
        if (dp[mask] === Infinity || mask === full) continue;
        let avail = 0;
        for (let i = 0; i < n; i++) {
            if (!(mask & (1 << i)) && (prereq[i] & mask) === prereq[i]) {
                avail |= (1 << i);
            }
        }
        let sub = avail;
        while (sub) {
            if (popcount(sub) <= k) {
                const newMask = mask | sub;
                if (dp[mask] + 1 < dp[newMask]) {
                    dp[newMask] = dp[mask] + 1;
                }
            }
            sub = (sub - 1) & avail;
        }
    }
    return dp[full];

    function popcount(x) {
        let c = 0;
        while (x) {
            c += x & 1;
            x >>>= 1;
        }
        return c;
    }
};
